  ('public-health-specialist-moex-00317', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '關於醫療法人與醫療機構之間的關係，下列何者正確？', '["一法人，多機構", "醫療法人與醫療機構處於同一對等地位", "醫療機構的存在，須以醫療法人存在為前提", "醫療機構與醫療法人一樣，同為權利主體，具享受權利、負擔義務之權利能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00318', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '藥事法所稱偽藥，係指藥品經稽查或檢驗有下列何種情形者？', '["擅自添加非法定著色劑、防腐劑、香料、矯味劑及賦形劑者", "所含有效成分之名稱，與核准不符者", "所含有效成分之質、量或強度，與核准不符者", "超過有效期間或保存期限者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00319', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '由於高齡化、少子化，臺灣全民健康保險財務面臨困境，醫療支出日益沉重。在調整健保財 務結構，將面臨現行一般保費法定費率上限，目前全民健康保險第一類至第三類被保險人及 其眷屬之保險費的保險費率上限為多少？', '["4.50%", "5.14%", "6.00%", "10.00%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00320', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '針對聘有外籍看護工家庭之被照顧者，經過長照需求評估且失能等級達第二級以上者可使用 長照2.0服務，有關服務使用下列敘述何者錯誤？', '["外籍看護工逃跑行蹤不明，被照顧者可申請包括照顧服務之所有長照服務", "外籍看護工返鄉回國期間之照顧空窗期，被照顧者可申請使用日間照顧服務", "被照顧者家屬如有照顧者支持服務需求者，無法使用家庭照顧者支持服務據點之支持服務", "被照顧者可使用照顧及專業服務額度的30%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00321', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '根據長期照顧服務法，其基金之來源不包含下列何者？', '["遺產稅及贈與稅稅率由10％調增至20％以內所增加之稅課收入", "菸酒稅菸品應徵稅額由每千支（每公斤）徵收新臺幣590元調增至新臺幣1590元所增加之 稅課收入", "政府預算撥充", "長照保險費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00322', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '關於傳染病病人權利保護，下列敘述何者錯誤？', '["隱私權為憲法明文列舉之權利", "政府機關、醫事機構、醫事人員及其他因業務知悉傳染病或疑似傳染病病人之姓名、病歷 及病史等有關資料者，不得洩漏", "傳染病或疑似傳染病病人之姓名、病歷及病史等有關資料，為依法應受法律保護之「個人資料」", "傳染病或疑似傳染病病人之隱私權所受法律保障並非絕對"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00323', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '傳染病防治法所稱傳染病，指下列由中央主管機關依致死率、發生率及傳播速度等危害風險 程度高低分類之疾病，共分幾類？', '["四類", "五類", "六類", "七類"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00324', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', 'WHO於1986年發表渥太華健康促進憲章，將「健康促進」定義為「使人們得以增加對其健 康的控制，即加以改善的過程」，透過三大角色採取五大優先行動，以增進群體健康並縮小健 康不平等，邁向全民均健。其中三大角色，不包含下列何者？', '["倡議（advocate）", "媒合（mediate）", "促能（enable）", "反思（reflect）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00325', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '根據食品安全衛生管理法，行政院應設「何種組織」，以加強全國食品安全事務之協調、監督、 推動及查緝，由行政院院長擔任召集人，召集相關部會首長、專家學者及民間團體代表共同 組成，職司跨部會協調食品安全風險評估及管理措施，建立食品安全衛生之預警及稽核制度， 至少每3個月開會一次，必要時得召開臨時會議？', '["食品安全會報", "食品藥物管理署藥品安全評估諮議小組", "食藥戰情中心", "食品衛生安全與營養諮議會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00326', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '根據菸害防制法對吸菸場所之限制，下列何者須全面禁止吸菸？', '["圖書館、博物館、美術館及其他文化或社會教育機構所在之室外場所", "室外體育場、游泳池或其他供公眾休閒娛樂之室外場所", "老人福利機構所在之室外場所", "政府機關及公營事業機構所在之室內場所"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00327', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '公共衛生實務與政策的介入面向上，公共衛生權責機構在擬定政策或證成（justify）政策的執 行，會訴諸「一般道德考量」（generalmoralconsiderations），其中首要道德考量為下列何者？', '["產生利益（producingbenefits）", "實現分配正義（distributivejustice）", "保護隱私與機密（protectingprivacyandconfidentiality）", "建立及維持信任（buildingandmaintainingtrust）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00328', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '近年來常發生民眾在急診或醫院救護現場大鬧恐嚇、脅迫護理人員，妨害到醫療救護工作， 這是違反何項法規？', '["職業安全衛生法", "重大醫療事故通報及處理辦法", "護理人員法", "醫療法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00329', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '病人自主權利法與安寧緩和醫療條例都與民眾在末期醫療的自主權有關，但兩者在某些層面 亦有些異同，下列敘述何者錯誤？', '["意願人預立醫療決定或簽署意願書時，皆須具完全行為能力者二人以上在場見證", "意願人預立醫療決定或簽署意願書時，兩者皆應註記於全民健康保險憑證，且意願人可隨 時以書面撤回其意願", "安寧緩和醫療條例是末期病人得立意願書選擇安寧緩和醫療或作維生醫療抉擇；而病人自 主權利法則是具完全行為能力之預立醫療決定，在特定臨床條件時，接受或拒絕維持生命 治療或人工營養及流體餵養之全部或一部分", "安寧緩和醫療條例之意願人、二親等內之親屬至少一人及醫療委任代理人應參與預立醫療 照護諮商；病人自主權利法則需意願人或其醫療委任代理人於意願書表示同意即可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00330', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '為減輕中、重度失能者接受機構式服務之家庭經濟負荷，衛生福利部自112年起調整「住宿 式服務機構使用者補助方案」，取消排富規定外，經評估符合長照需要等級多少以上之住民， 每人每年最高可補助12萬元？', '["第四級以上", "第五級以上", "第六級以上", "第七級以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00331', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關申請長期照顧服務機構設立許可，下列敘述何者正確？', '["居家式服務類應先申請籌設許可再申請設立許可", "申請日間照顧中心籌設時，若承租非申請人之私人土地或建物，需檢附公證之租賃契約且 期限須至少10年", "申請人為公司或商號者，應檢附載明辦理長期照顧服務之所營事業登記預查證明", "申請提供家庭托顧服務之長照機構籌設許可，以法人為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00332', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列何種資訊會註記於全民健康保險憑證？①愛滋病感染者  ②同意器官捐贈者  ③重大傷病者', '["簽署病人自主權相關文件者  ⑤簽署DNR（Do-Not-Resuscitate）", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00333', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '我國所公告之「罕見疾病」，係依「罕見疾病防治及藥物法」及罕見疾病審議認定原則之規定， 指疾病盛行率在中央主管機關公告基準多少以下或因情況特殊，經罕見疾病及藥物審議會審 議認定之？', '["萬分之一", "十萬分之一", "百萬分之一", "依疾病嚴重度及治療決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00334', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '近年社會屢有精神疾病患者之犯罪案件，喚起大眾對精神疾病患者的強制就醫治療的關注。 強制治療需在個人自主權的限制與社會安全間取得平衡，在無其他侵害較小的方法下，對精 神疾病患者執行強制治療可視為具有其正當性，以此論述這是基於何項法律原則？', '["明確性原則", "法律保留原則", "公益原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00335', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', 'COVID-19 期間的確診者需透過疫情調查以匡列接觸者，除了保護密切接觸者之外，也是為 了避免疫情擴散，但也因此在確診者的隱私權與接觸者的健康權之間產生衝突。下列有關此 現象的倫理論述何者錯誤？', '["當密切接觸者處於重大感染的風險下，感染者負有對其揭露感染風險資訊，以保護接觸者 之倫理義務", "公衛人員基於防治需要的正當理由，在符合傷害原則與弱勢原則下，有告知密切接觸者感 染風險之義務", "違反確診者意願而強制取得其接觸史，甚至將其確診的事實告知第三者，有侵害確診者自 主權之虞", "在疫情嚴峻情況下，缺乏其他侵害最小之方法而採取強制隔離，會造成受隔離者人格權重 大影響，牴觸比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00336', 'public-health-specialist', 'public-health-specialist-moex-113-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '傳染病防治法第48條第1項規定：「主管機關對於曾與傳染病病人接觸或疑似被傳染者，得 予以留驗；必要時，並得令遷入指定之處所檢查、施行預防接種、投藥、指定特定區域實施 管制或隔離等必要之處置。」依此法條文義及立法目的，這是基於何項法律原則？', '["法律保留原則", "明確性原則", "公益原則", "比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "7368e33a3bb2", "answer_pdf_sha1": "2e796a3408fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
